# tests/test_sanitizer.py
import pytest
import json
from pathlib import Path
from security.sanitizer import sanitize_html, HTMLSanitizer


class TestSanitizeBasicTags:
    """Test that safe tags are preserved."""

    def test_bold_tags_preserved(self):
        assert sanitize_html("<b>hello</b>") == "<b>hello</b>"
        assert sanitize_html("<strong>hello</strong>") == "<strong>hello</strong>"

    def test_italic_tags_preserved(self):
        assert sanitize_html("<i>hello</i>") == "<i>hello</i>"
        assert sanitize_html("<em>hello</em>") == "<em>hello</em>"

    def test_link_tags_preserved(self):
        result = sanitize_html('<a href="https://example.com">link</a>')
        assert '<a href="https://example.com">link</a>' == result

    def test_list_tags_preserved(self):
        html = "<ul><li>item 1</li><li>item 2</li></ul>"
        assert sanitize_html(html) == html

    def test_ordered_list_preserved(self):
        html = "<ol><li>first</li><li>second</li></ol>"
        assert sanitize_html(html) == html

    def test_image_tags_preserved(self):
        result = sanitize_html('<img src="https://example.com/pic.png" alt="photo">')
        assert 'src="https://example.com/pic.png"' in result
        assert 'alt="photo"' in result

    def test_paragraph_tags_preserved(self):
        assert sanitize_html("<p>text</p>") == "<p>text</p>"

    def test_br_tags_preserved(self):
        assert sanitize_html("line1<br>line2") == "line1<br>line2"


class TestSanitizeXSSVectors:
    """Test that common XSS vectors are stripped."""

    def test_script_tag_removed(self):
        result = sanitize_html('<script>alert("xss")</script>')
        assert '<script>' not in result
        assert 'alert' not in result

    def test_script_tag_variations(self):
        result = sanitize_html('<SCRIPT>alert(1)</SCRIPT>')
        assert 'script' not in result.lower()
        assert 'alert' not in result

    def test_onclick_handler_removed(self):
        result = sanitize_html('<div onclick="alert(1)">text</div>')
        assert 'onclick' not in result

    def test_onerror_handler_removed(self):
        result = sanitize_html('<img src=x onerror="alert(1)">')
        assert 'onerror' not in result

    def test_onmouseover_handler_removed(self):
        result = sanitize_html('<a onmouseover="alert(1)">link</a>')
        assert 'onmouseover' not in result

    def test_javascript_url_in_href(self):
        result = sanitize_html('<a href="javascript:alert(1)">click</a>')
        assert 'javascript:' not in result

    def test_javascript_url_in_img_src(self):
        result = sanitize_html('<img src="javascript:alert(1)">')
        assert 'javascript:' not in result

    def test_iframe_removed(self):
        result = sanitize_html('<iframe src="https://evil.com"></iframe>')
        assert '<iframe' not in result

    def test_object_embed_removed(self):
        result = sanitize_html('<object data="evil.swf"><embed src="evil.swf"></object>')
        assert '<object' not in result
        assert '<embed' not in result

    def test_form_removed(self):
        result = sanitize_html('<form action="https://evil.com"><input type="text"></form>')
        assert '<form' not in result

    def test_meta_refresh_removed(self):
        result = sanitize_html('<meta http-equiv="refresh" content="0;url=https://evil.com">')
        assert '<meta' not in result

    def test_data_url_removed(self):
        result = sanitize_html('<a href="data:text/html,<script>alert(1)</script>">click</a>')
        assert 'data:' not in result


class TestSanitizeEdgeCases:
    """Test edge cases and encoding tricks."""

    def test_nested_script_tags(self):
        result = sanitize_html('<scr<script>ipt>alert(1)</script>')
        assert 'alert' not in result

    def test_null_bytes_in_tag(self):
        result = sanitize_html('<scri\x00pt>alert(1)</script>')
        assert 'alert' not in result

    def test_plain_text_unchanged(self):
        assert sanitize_html("Hello, world!") == "Hello, world!"

    def test_empty_string(self):
        assert sanitize_html("") == ""

    def test_entities_preserved(self):
        result = sanitize_html("&amp; &lt; &gt;")
        assert "&amp;" in result or "&" in result

    def test_mixed_safe_and_unsafe(self):
        html = '<b>bold</b><script>alert(1)</script><i>italic</i>'
        result = sanitize_html(html)
        assert '<b>bold</b>' in result
        assert '<i>italic</i>' in result
        assert 'script' not in result.lower()
        assert 'alert' not in result


class TestSanitizeFromPayloads:
    """Run tests from the XSS payloads file."""

    @pytest.fixture
    def payloads(self):
        payload_file = Path(__file__).parent / "xss_payloads.json"
        with open(payload_file) as f:
            return json.load(f)

    def test_all_payloads_neutralized(self, payloads):
        for entry in payloads:
            payload = entry["payload"]
            result = sanitize_html(payload)
            # The dangerous part should be gone
            for dangerous in entry.get("must_not_contain", []):
                assert dangerous.lower() not in result.lower(), (
                    f"Payload not sanitized: {payload!r} — "
                    f"found '{dangerous}' in result: {result!r}"
                )

